import sys

def read_ints():
    return map(int, sys.stdin.readline().strip().split())


def main():
    n = int(sys.stdin.readline().strip())
    i = 0
    while n > 0:
        i += 1
        n -= i
    if n == 0:
        print(i)
    else:
        print(i - 1)


if __name__ == '__main__':
    main()
